var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"짠-!","JPN":"ジャーン！","ENG":"Ta-da!","TWN":"鏘～"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"이건 오늘 새로 생긴 어플이야.","JPN":"これはね、今日新しくできたアプリなの！","ENG":"This is a new application that was released today.","TWN":"這是今天新做的應用程式。"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>래빗 센스</color>라고 지었어!","JPN":"名前は<color=#ffd34c>ラビットセンス</color>にしたんだ！","ENG":"I named it <color=#ffd34c>Rabbit Sense</color>!","TWN":"<color=#ffd34c>兔兔感應</color>！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"역시 하림 대장! 하루가 다르게 발전하는 모습이 대단하다.","JPN":"さすが、ウサギ隊長！　日々成長する姿、素晴らしい。","ENG":"That's great, Captain Harim! It's amazing how you improve yourself on a daily basis.","TWN":"不愧是夏琳隊長！日新月異，太厲害了！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇담 래빗 센스의 기능은 뭔가, 대장?","JPN":"隊長、それでそのラビットセンスの機能は？","ENG":"Captain, what are the functions of Rabbit Sense?","TWN":"所以兔兔感應的功能是什麼，隊長？"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"엣헴-! 그건 바로, 도움을 필요로 하는 동물의 신호를 감지하는 것이지!","JPN":"えっへん！　これで助けを必要とする動物たちの信号を感知できるの！","ENG":"Ahem! This application is capable of detecting signals from animals that need help!","TWN":"欸嘿～！那就是，可以偵測到需要幫助的動物信號！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 이거 봐! 여기 이 빨간 점!","JPN":"あっ、見て！　この赤い点！","ENG":"Oh, look at this! The red dot here!","TWN":"啊，看這個！這個紅色的點！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"도와달라는 동물의 신호야! 가까운 곳에 있어!","JPN":"助けを求めてる動物の信号だよ！　ここのすぐ近くだ！","ENG":"It's a signal for help from an animal! It's very close!","TWN":"是尋求幫助的動物信號！就在附近！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어서 가 보자!","JPN":"行ってみよう！","ENG":"Let's go check it out!","TWN":"我們快去吧！"},"stage":{"bg":"CAFE","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"대장, 누가 나무에 매달려 있어. 저 사람이 구조신호를 보낸 거야?","JPN":"ウサギ隊長、誰かが木に\\nぶら下がっている。あの人が信号を発したのか？","ENG":"Captain, someone's hanging on the tree. Is she the one who sent the signal?","TWN":"隊長，有個人吊在樹上耶，會不會是那個人發出的求救信號？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으응...... 아마도 그렇겠지? 내가 생각한 동물이랑은 다른 것 같지만......","JPN":"う～ん……そうかも？\\n僕の言う動物とはちょっと違ったけど……","ENG":"Um... I guess so? Although she's a bit different from what I imagined...","TWN":"嗯……應該是吧，雖然和我想像的不一樣……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헤헤, 얘들아 안녕?","JPN":"へへっ、やっほ～！","ENG":"Heh. Hi, girls.","TWN":"嘿嘿，你們好啊？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"거기 나무 위에 계신 위기의 여성 분!","JPN":"そこの木の上にいる女性の方！","ENG":"Hello, distressed lady up a tree!","TWN":"那邊吊在樹上，陷入危機的女士！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"도움이 필요하시면 말씀만 하세요!","JPN":"お困りでしたら言ってください！","ENG":"Just tell me if you need help!","TWN":"如果妳需要幫忙的話，請直接說吧！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"저희 이래 봬도 카운터니까요!","JPN":"僕たちこう見えてもカウンターなんです！","ENG":"We're both qualified Counters!","TWN":"別看我們這樣，我們可是制裁者喔！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응? 아냐, 괜찮아.","JPN":"え？　ううん、別に困ってないけど。","ENG":"Huh? Oh, I'm fine.","TWN":"嗯？不用，沒關係的。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"......읏차!","JPN":"……よいしょっ！","ENG":"Ha!","TWN":"……嘿咻！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG_02"},{"id":"L31_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"뛰, 뛰어내렸다. 방금 땅이 울렸어......","JPN":"と、飛び降りた。今、地響きがしたような……？","ENG":"S-she jumped. And the ground just shook...","TWN":"跳，跳下來了。地面好像震了一下……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 무릎 괜찮아요? 다치진 않았어요?","JPN":"膝は大丈夫ですか？　怪我とかしてないですか？","ENG":"Oh, are your knees okay? Are you hurt anywhere?","TWN":"啊，膝蓋沒事嗎？沒有受傷吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응, 난 멀쩡해. 위에서 고양이가 울고 있길래 구해줬을 뿐인걸.","JPN":"うん、私は平気だよ。木の上で\\nネコちゃんが鳴いてたから、助けてあげたの。","ENG":"Yeah, I'm fine. I was just helping out a cat that was stuck in the tree.","TWN":"我沒事，我只是看小貓在上面叫，把牠救下來了而已。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"야옹~","JPN":"にゃあ～。","ENG":"Meow!","TWN":"喵喵～"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L39_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 고양아! 너였구나!","JPN":"あっ、ネコだ！　あなただったのね？","ENG":"Oh, a kitty! It was you!","TWN":"啊，小貓咪！原來是你啊！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이 고양이를 알아? 혹시 네가 고양이 주인?","JPN":"このネコちゃん、知ってるの？　もしかして飼い主とか？","ENG":"Do you know this cat? Are you the owner?","TWN":"妳認識這隻貓？妳是牠的主人嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 아뇨. 이건 그러니까 말하자면......","JPN":"あっ、いえ。えっと、何ていうか……","ENG":"N-no. How should I explain this...","TWN":"不、不是。這是因為……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하림 언니는 도움을 원하는 동물이 어디에 있는지 래빗센스로 알 수 있다!","JPN":"ウサギ隊長は助けを求めてる動物がどこにいるか、ラビットセンスで把握することができるんだ！","ENG":"Harim is able to identify where a distress animal is located with her Rabbit Sense!","TWN":"夏琳姐姐是用兔兔感應，才知道需要幫助的動物在哪的！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"굉장한 능력이지!","JPN":"すごい能力だ！","ENG":"It's an incredible ability!","TWN":"是個很棒的能力！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와, 그런 능력을 써서 동물들을 구조하다니, 엄청 멋지다!","JPN":"わぁ、そんな能力を使って\\n動物たちを助けてるなんて素敵だね！","ENG":"Wow, you're using your ability to help animals? That's so cool!","TWN":"哇，居然使用這種能力去救助動物們，真是太帥了！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"더 감탄해도 좋다. 하림 대장에겐 훨씬 굉장한 능력이 백 가지는 더 있으니까.","JPN":"ウサギ隊長には、もっと素晴らしい能力が100個以上はあるのだ！","ENG":"You are free to feel more impressed. Captain Harim has at least 100 more incredible abilities.","TWN":"妳可以再佩服一點沒關係，夏琳隊長還有一百多個比這更厲害的能力呢。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하하...... 소림아 그 정도까진 아닌데......","JPN":"はは……そこまでじゃないけどなぁ……","ENG":"Hah hah... Sorim, don't exaggerate...","TWN":"哈哈……蕭林，我沒有那麼厲害啦……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 이것 봐! 이번엔 다른 곳에서 구조신호가!","JPN":"あっ、これ見て！　今度は他のところから救助信号が！","ENG":"Oh, look! There's another signal coming from elsewhere!","TWN":"啊，看這個！這次是從別的地方傳來的求救信號！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"위기에 빠진 동물을 구하러 가는 거지?","JPN":"助けを求めてる動物を助けに行くの？","ENG":"Are you going to help another distressed animal?","TWN":"你們是要去幫助陷入危險的動物們吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"좋아. 나도 도울게.","JPN":"よしっ、私も手伝う！","ENG":"Alright, I'll help out as well.","TWN":"很好，我也去幫忙吧。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 어, 굳이 그러지 않으셔도......","JPN":"はい？　いや、そこまでしていただかなくても……","ENG":"Huh? Uh, you really don't have to...","TWN":"什麼？呃，沒關係，妳不用非要跟我們去……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"휴, 그렇게까지 함께하길 원한다면 어쩔 수 없군.","JPN":"ふぅ、そこまで言うなら仕方ない。","ENG":"*Sigh* If that is your true desire, I guess we have no choice.","TWN":"唉，妳要是這麼想和我們一起去的話，真拿妳沒辨法呢。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"응?","JPN":"えっ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"동물 구조대 화이트 래빗의 일원이 된 걸 환영한다, 제군.","JPN":"アニマルレスキュースペシャルフォース\\nホワイトラビットの一員となったことを歓迎する。","ENG":"Welcome to the Animal Rescue Team, White Rabbit, soldier.","TWN":"歡迎妳成為動物救助隊白兔社的一員，隊員。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"이분은 우리들의 리더인 양하림 대장. 그리고 본관을 부를 땐 편하게 한소림 부대장이라고 부르도록.","JPN":"こちらは我々のリーダーであるホシノ・ウサギ隊長。\\nそして本官はハネダ・ミズキ部隊長と呼ぶように。","ENG":"This here is our leader, Captain Yang Harim. And you may address me as Adjutant Han Sorim.","TWN":"這位是我們的隊長楊夏琳，然後妳稱呼本官的時候，要叫我蕭林副隊長。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하림이랑 소림이구나? 난 조호진이야. 잘 부탁해!","JPN":"ウサギちゃんとミズキちゃんね？　私はイトウ・マユミ、よろしくね！","ENG":"Harim and Sorim? My name is Cho Hojin. Nice to meet you!","TWN":"原來是夏琳和蕭林啊？我叫趙鎬眞，請多指教！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"나, 난 부대장이니까 존칭으로 불러주면 좋겠는데...... 요.","JPN":"ほ、本官は部隊長だ。\\n敬称をつけて呼んでもらいたい……です。","ENG":"I-I would prefer it if you address me as the Adjutant... Please?","TWN":"我、我是副隊長，所以妳得用敬稱叫……我。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자아, 그럼 동물들을 구하러 가 볼까? 렛츠 고!","JPN":"それじゃ、動物たちを助けに行こっか？　レッツゴー！","ENG":"Alright, time to go save our animal friends! Let's go!","TWN":"來吧，那我們就去拯救需要幫助的動物們吧？Let‘s go！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"먼저 가버렸네......","JPN":"先に行っちゃったね……","ENG":"There she goes...","TWN":"先走掉了呢……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"좋은 사람인 것 같긴 한데......","JPN":"良い人そうだけど……","ENG":"She seems like a good person, but...","TWN":"看起來是個好人，可是……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"......저기요! 신호는 거기가 아니라 반대쪽이에요!","JPN":"……あの！　信号はそっちじゃなくて反対側です！","ENG":"Excuse me! The signal is coming from the opposite direction!","TWN":"……那個！信號不在那裡，是反方向！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};